package pt.isep.enorm.ref.security;

/*Generated by MPS */

import org.springframework.stereotype.Service;
import org.springframework.security.core.userdetails.UserDetailsService;
import pt.isep.enorm.ref.repository.UserTypeRepository;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UsernameNotFoundException;

@Service
public class UserTypeDetailsService implements UserDetailsService {
  private final UserTypeRepository userTypeRepository;
  public UserTypeDetailsService(UserTypeRepository userTypeRepository) {
    this.userTypeRepository = userTypeRepository;
  }
  @Override
  public UserDetails loadUserByUsername(final String username) throws UsernameNotFoundException {
    return userTypeRepository.findByUsername(username).orElseThrow(() -> new UsernameNotFoundException("User not found: " + username));
  }
}
